function saveAllegory(concept, style, imageUrl, explanation) {
  const allegories = JSON.parse(localStorage.getItem('allegories') || '[]');
  allegories.unshift({ concept, style, imageUrl, explanation, timestamp: new Date().toISOString() });
  localStorage.setItem('allegories', JSON.stringify(allegories));
}

function getAllegories() {
  return JSON.parse(localStorage.getItem('allegories') || '[]');
}
